#include <bits/stdc++.h>
using namespace std;

const int N=5e4+10,V=1e8+1;

struct Node{
    int sum,lc,rc;
}t[N*610];

int n,m,a[N],root[N],tot;

void modify(int p,int l,int r,int x,int k){
    if(l==r){
        t[p].sum+=k;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid){
        if(!t[p].lc) t[p].lc=++tot;
        modify(t[p].lc,l,mid,x,k);
    }else{
        if(!t[p].rc) t[p].rc=++tot;
        modify(t[p].rc,mid+1,r,x,k);
    }
    t[p].sum=t[t[p].lc].sum+t[t[p].rc].sum;
}

int query(int p,int l,int r,int x){
    if(r<=x || !p)
        return t[p].sum;
    int mid=l+r>>1;
    if(x<=mid)
        return query(t[p].lc,l,mid,x);
    return t[t[p].lc].sum+query(t[p].rc,mid+1,r,x);
}

void add(int x,int y,int k){
    for(;x<=n;x+=(x&(-x)))
        modify(root[x],-1,V,y,k);
}

int ask(int x,int y){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=query(root[x],-1,V,y);
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        root[i]=++tot;
        for(int j=i-(i&(-i))+1;j<=i;j++)
            modify(root[i],-1,V,a[j],1);
    }
    while(m--){
        int op,x,y,k;
        scanf("%d",&op);
        if(op==1){
            scanf("%d%d%d",&x,&y,&k);
            printf("%d\n",ask(y,k-1)-ask(x-1,k-1)+1);
        }else if(op==2){
            scanf("%d%d%d",&x,&y,&k);
            int l=0,r=V;
            while(l<r){
                int mid=l+r+1>>1;
                if(ask(y,mid-1)-ask(x-1,mid-1)+1<=k)
                    l=mid;
                else
                    r=mid-1;
            }
            printf("%d\n",l);
        }else if(op==3){
            scanf("%d%d",&x,&k);
            add(x,a[x],-1);
            add(x,k,1);
            a[x]=k;
        }else if(op==4){
            scanf("%d%d%d",&x,&y,&k);
            int l=-1,r=k-1,rnk=ask(y,k-1)-ask(x-1,k-1);
            while(l<r){
                int mid=l+r>>1;
                if(ask(y,mid)-ask(x-1,mid)>=rnk)
                    r=mid;
                else
                    l=mid+1;
            }
            if(~l)
                printf("%d\n",l);
            else
                puts("-2147483647");
        }else if(op==5){
            scanf("%d%d%d",&x,&y,&k);
            int l=k+1,r=V,rnk=ask(y,k)-ask(x-1,k);
            while(l<r){
                int mid=l+r+1>>1;
                if(ask(y,mid-1)-ask(x-1,mid-1)<=rnk)
                    l=mid;
                else
                    r=mid-1;
            }
            if(r==V)
                puts("2147483647");
            else
                printf("%d\n",l);
        }
    }
    return 0;
}
